package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.CategorieKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.CategorieKengetalStatuutFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.CategorieKengetalStatuutPensioenstelselFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.StatuutFactory;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Rekenwijze;
import be.schaubroeck.lpb.tools.enumtypes.RszppoKategorie;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetal;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuut;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.Statuut;
import lombok.Getter;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

import static be.schaubroeck.lpb.tools.enumtypes.Konstanten.KST_INDEX;
import static be.schaubroeck.lpb.tools.enumtypes.Konstanten.KST_INDEX2;
import static be.schaubroeck.lpb.tools.enumtypes.Konstanten.KST_INDEX_FED;

@Getter
public class Indexator {

    private final BigDecimal index;
    private final BigDecimal index2;
    private final BigDecimal afwijkendeIndexFederaal;
    private final RkmTijdperk tijdperk;

    public Indexator(BigDecimal index, BigDecimal afwijkendeIndexFederaal, LocalDate selectieDatum) {
        this.index = index;
        this.index2 = index;
        this.afwijkendeIndexFederaal = afwijkendeIndexFederaal;
        this.tijdperk = RkmTijdperk.getTijdperk(selectieDatum);
    }

    public Indexator(ConstantManager constantManager, LocalDate selectieDatum) {
        this.index = constantManager.getByCodeDatum(KST_INDEX, selectieDatum).getProcentFactor();
        this.index2 = constantManager.getByCodeDatum(KST_INDEX2, selectieDatum).getProcentFactor();
        Constant constant = constantManager.getByCodeDatumSafe(KST_INDEX_FED.getCode(), selectieDatum);
        this.afwijkendeIndexFederaal = constant != null ? constant.getProcentFactor() : BigDecimal.ZERO;
        this.tijdperk = RkmTijdperk.getTijdperk(selectieDatum);
    }

    /*
     * http://superwiki/lpb/32637-sw.html
     */
    public Money indexeer(Money bedrag, AardKodeExtensie looncode, SleutelGegevens aggregaat) {
        return indexeer(bedrag, looncode.getLn_indexatie() == 1, aggregaat);
    }

    public Money indexeer(Money bedrag, Opper opper) {
        SleutelGegevens aggregaat = new SleutelGegevensSingleOpper(opper);
        return indexeer(bedrag, true, aggregaat);
    }

    private Money indexeer(Money bedrag, boolean indexeer, SleutelGegevens aggregaat) {
        if (aggregaat.getHoedanigheid() != Hoedanigheid.WACHTWEDDEN && indexeer) {
            BigDecimal indexToBeUsed = bepaalGebruikteIndex(aggregaat);
            bedrag = bedrag.multiply(indexToBeUsed);
        }
        return bedrag;
    }

    public BigDecimal bepaalIndex(SleutelGegevens aggregaat) {
        if (gebruiktIndex2(aggregaat)) {
            return index2;
        } else if (aggregaat.isAfwijkendeIndexFederaal() && afwijkendeIndexFederaal != null) {
            return afwijkendeIndexFederaal;
        } else {
            return index;
        }
    }

    public BigDecimal bepaalIndex(Opper opper) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return bepaalIndex(gegevens);
    }

    public BigDecimal bepaalGebruikteIndex(Opper opper) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return bepaalGebruikteIndex(gegevens);
    }

    public BigDecimal bepaalGebruikteIndex(SleutelGegevens aggregaat) {
        BigDecimal indexToBeUsed = bepaalIndex(aggregaat);
        BigDecimal afwijkendeIndex = aggregaat.getAfwijkendeIndex().movePointLeft(2);
        indexToBeUsed = afwijkendeIndex.signum() != 0 ? afwijkendeIndex : indexToBeUsed;
        return indexToBeUsed;
    }

    public Money indexeer(Money bedrag, AardKodeExtensie looncode, Opper opper) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return indexeer(bedrag, looncode, gegevens);
    }

    public boolean gebruiktIndex2(SleutelGegevens aggregaat) {
        boolean gebruiktIndex2 = false;
        Hoedanigheid hoedanigheid = aggregaat.getHoedanigheid();
        Rekenwijze rekenwijze = aggregaat.getRekenWijze();
        if (hoedanigheid == Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES && rekenwijze == Rekenwijze.MAAND) {
            if (tijdperk == RkmTijdperk.RSZPPO) {
                RszppoKategorie categorie = aggregaat.getCategorie();
                gebruiktIndex2 = categorie == RszppoKategorie.OW_NG_PU || categorie == RszppoKategorie.N_GESUB_GP;
            } else {
                DmfapplStatuutDmfappl statuutDmfAPPL = aggregaat.getStatuutDmfappl();
                WerkgeversCategorie werkgeversCategorie = aggregaat.getWerkgeversCategorie();
                DmfapplWnkengetal werknemersKengetal = aggregaat.getWerknemersKengetal();
                CategorieKengetal categorieKengetal =
                        CategorieKengetalFactory.getCategorieKengetal(tijdperk, werkgeversCategorie, werknemersKengetal);
                CategorieKengetalStatuut categorieKengetalStatuut =
                        CategorieKengetalStatuutFactory.getCategorieKengetalStatuut(tijdperk, categorieKengetal, statuutDmfAPPL);
                CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel =
                        CategorieKengetalStatuutPensioenstelselFactory.create(tijdperk, categorieKengetalStatuut, aggregaat.getPensioenStelsel());
                Statuut statuut = StatuutFactory.create(tijdperk, statuutDmfAPPL);
                gebruiktIndex2 = statuut.isPersoneelOnderwijs() && categorieKengetalStatuutPensioenstelsel.isIndex2();
            }
        }
        return gebruiktIndex2;
    }

    public Money indexeerGrensBedragen(Money bedrag, SleutelGegevens aggregaat) {
        BigDecimal indexToBeUsed = bepaalIndex(aggregaat);
        bedrag = bedrag.multiply(indexToBeUsed);
        return bedrag;
    }


    public static Money deIndexeer(BigDecimal index, Money bedrag, AardKodeExtensie looncode, Opper opper, boolean negeerIndexatie) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return deIndexeer(index, bedrag, looncode, gegevens, negeerIndexatie);
    }

    public static Money deIndexeer(BigDecimal index, Money bedrag, AardKodeExtensie looncode, SleutelGegevens aggregaat, boolean negeerIndexatie) {
        if (aggregaat.getHoedanigheid() != Hoedanigheid.WACHTWEDDEN && (looncode.getLn_indexatie() == 1 || negeerIndexatie)) {
            BigDecimal afwijkendeIndex = aggregaat.getAfwijkendeIndex().movePointLeft(2);
            index = afwijkendeIndex.signum() != 0 ? afwijkendeIndex : index;
            bedrag = bedrag.divide(index);
        }
        return bedrag;
    }


}
